.live-deal-card {
  background: #141414; border: 1px solid #2A2A2A;
  border-radius: 18px; overflow: hidden;
  transition: transform 0.22s, border-color 0.22s, box-shadow 0.22s;
}
.live-deal-card:hover {
  transform: translateY(-5px); border-color: var(--gold-border);
  box-shadow: 0 16px 50px rgba(0,0,0,0.45);
}
.live-deal-gallery {
  position: relative; width: 100%; aspect-ratio: 16 / 10; overflow: hidden;
  background: #141414; contain: layout style;
}
.live-deal-gallery img {
  width: 100%; height: 100%; object-fit: cover; display: block;
}
.live-deal-no-photo {
  width: 100%; aspect-ratio: 16 / 10; display: flex; flex-direction: column;
  align-items: center; justify-content: center; gap: 8px;
  background: #141414; color: var(--text3); font-size: 12px;
}
.live-deal-overlay-badge {
  position: absolute; top: 10px; left: 10px;
  display: flex; align-items: center; gap: 5px;
  background: rgba(0,196,140,0.2); border: 1px solid rgba(0,196,140,0.4);
  border-radius: 10px; padding: 5px 10px;
  font-size: 9px; font-weight: 900; color: var(--green);
  letter-spacing: 1.5px;
}
.live-deal-overlay-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--green); animation: glow-pulse 1.8s infinite;
}
.live-deal-source-badge {
  display: none !important;
}
.live-deal-source-badge.db {
  background: rgba(34,197,94,0.16); border: 1px solid rgba(34,197,94,0.3); color: #7EF7A7;
}
.live-deal-source-badge.storage {
  background: rgba(74,144,217,0.16); border: 1px solid rgba(74,144,217,0.3); color: #7CC4FF;
}
.live-deal-source-badge.fallback {
  background: rgba(255,215,0,0.16); border: 1px solid rgba(255,215,0,0.3); color: var(--gold);
}
.live-deal-source-badge.missing {
  background: rgba(255,77,77,0.16); border: 1px solid rgba(255,77,77,0.3); color: #FF8C8C;
}
.live-deal-verified-badge {
  position: absolute; top: 10px; right: 10px;
  display: flex; align-items: center; gap: 4px;
  background: rgba(0,196,140,0.15); border: 1px solid rgba(0,196,140,0.3);
  border-radius: 10px; padding: 5px 9px;
  font-size: 9px; font-weight: 800; color: var(--green);
  letter-spacing: 0.5px;
}
.live-deal-roi-badge {
  position: absolute; top: 10px; right: 10px;
  background: rgba(0,196,140,0.14); border: 1px solid rgba(0,196,140,0.28);
  border-radius: 100px; padding: 4px 10px;
  font-size: 11px; font-weight: 800; color: var(--green);
  backdrop-filter: blur(8px);
}
.live-deal-photo-count {
  position: absolute; bottom: 10px; right: 10px;
  background: rgba(0,0,0,0.65); border-radius: 10px; padding: 4px 9px;
  font-size: 11px; color: #fff; font-weight: 700; letter-spacing: 0.3px;
}
.live-deal-photo-dots {
  position: absolute; bottom: 10px; left: 0; right: 0;
  display: flex; justify-content: center; gap: 5px;
}
.live-deal-photo-dot {
  width: 6px; height: 6px; border-radius: 3px;
  background: rgba(255,255,255,0.35);
}
.live-deal-photo-dot.active {
  width: 18px; background: var(--gold); border-radius: 3px;
}
.live-deal-content { padding: 18px; }
.live-deal-header-row {
  display: flex; align-items: flex-start; justify-content: space-between; gap: 12px; flex-wrap: wrap;
}
.live-deal-sale-pill {
  min-width: 118px; max-width: 100%;
}
.live-deal-title {
  font-size: 20px; font-weight: 900; margin-bottom: 4px;
  letter-spacing: -0.3px; color: #FFFFFF;
}
.live-deal-location {
  display: flex; align-items: center; gap: 4px;
  font-size: 13px; color: #9A9A9A; margin-bottom: 2px;
}
.live-deal-divider {
  height: 1px; background: #2A2A2A; margin: 14px 0;
}
.live-deal-metrics {
  display: flex; align-items: center; margin-bottom: 0;
}
.live-deal-metric {
  flex: 1; text-align: center;
}
.live-deal-metric-val {
  font-size: 18px; font-weight: 900; margin-bottom: 3px;
  letter-spacing: -0.3px; color: #FFFFFF;
}
.live-deal-metric-lbl {
  font-size: 11px; color: #6A6A6A;
}
.live-deal-metric-div {
  width: 1px; height: 32px; background: #2A2A2A;
}
.live-deal-market-strip {
  display: flex; gap: 8px; margin-bottom: 10px;
}
.live-deal-market-pill {
  flex: 1; background: #242424; border-radius: 12px;
  padding: 10px;
}
.live-deal-market-pill-label {
  color: #666666; font-size: 10px; font-weight: 700;
  text-transform: uppercase; letter-spacing: 0.6px; margin-bottom: 4px;
}
.live-deal-market-pill-value {
  color: #FFFFFF; font-size: 13px; font-weight: 800;
}
.live-deal-ownership-hint {
  color: #999999; font-size: 12px; line-height: 18px; margin-bottom: 12px;
}
.live-deal-developer-row {
  display: flex; align-items: center; justify-content: center;
  gap: 6px; margin-bottom: 12px; flex-wrap: wrap;
}
.live-deal-developer-icon {
  width: 16px; height: 16px; display: flex; align-items: center;
  justify-content: center; color: var(--gold); flex-shrink: 0;
}
.live-deal-developer-text {
  font-size: 13px; color: #9A9A9A;
}
.live-deal-developer-name {
  color: #FFFFFF; font-weight: 700;
}
.live-deal-trust-indicators {
  display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 16px;
}
.live-deal-trust-badge {
  display: inline-flex; align-items: center; gap: 4px;
  background: #1A1A1A; border-radius: 8px;
  padding: 5px 8px; font-size: 10px; font-weight: 600;
  color: #9A9A9A;
}
.live-deal-actions {
  display: flex; gap: 10px; margin-bottom: 10px;
  align-items: stretch;
}
@media (max-width: 520px) {
  .live-deal-header-row {
    flex-direction: column;
    align-items: stretch;
  }
  .live-deal-sale-pill {
    width: 100%;
  }
  .live-deal-actions {
    flex-direction: column;
  }
  .live-deal-details-btn,
  .live-deal-invest-btn {
    width: 100%;
    min-width: 0;
  }
  .live-deal-photo-count {
    bottom: 12px;
    right: 12px;
  }
  .live-deal-title {
    font-size: 18px;
    line-height: 1.12;
  }
  .live-deal-developer-text {
    text-align: center;
  }
}
.live-deal-details-btn {
  flex: 1; display: flex; align-items: center; justify-content: center;
  padding: 14px; border-radius: 12px;
  border: 1.5px solid #2A2A2A; background: #141414;
  font-size: 15px; font-weight: 700; color: #FFFFFF;
  cursor: pointer; font-family: inherit;
  transition: border-color 0.2s, transform 0.15s;
}
.live-deal-details-btn:hover {
  border-color: var(--gold-border); transform: translateY(-1px);
}
.live-deal-invest-btn {
  flex: 1; display: flex; align-items: center;
  justify-content: center;
  background: var(--gold); color: #000;
  font-weight: 900; font-size: 15px;
  padding: 14px; border-radius: 12px;
  border: none; cursor: pointer; font-family: inherit;
  transition: background 0.2s, transform 0.15s;
}
.live-deal-invest-btn:hover {
  background: var(--gold-light); transform: translateY(-2px);
}
.live-deal-min-invest {
  background: #1A1A1A; border-radius: 10px;
  padding: 8px 14px; text-align: center;
  font-size: 13px; color: #9A9A9A;
}
.live-deal-min-invest strong {
  color: #FFFFFF; font-weight: 800;
}
.live-deals-loading {
  text-align: center; padding: 40px 20px;
  color: var(--text3); font-size: 13px;
}
.live-deals-loading .spinner {
  width: 28px; height: 28px; border: 3px solid var(--border);
  border-top-color: var(--gold); border-radius: 50%;
  animation: spin 0.8s linear infinite;
  margin: 0 auto 12px;
}
@keyframes spin { to { transform: rotate(360deg); } }

